import { branchLabel, computeReachableSteps, nextRefsForMode, resolvePerTarget, resolveTargetableString, } from "./schema.js";
/** Diagrams use the `default` (or claude) variant of any per-target string. */
const DIAGRAM_TARGET = "claude";
/**
 * Produce a Mermaid flowchart from the flow's schema alone — no prose or
 * body content is read. Each mode is rendered as a labeled edge so a viewer
 * can see exactly where the modes diverge.
 *
 * The graph derives entirely from `entries`, `next`, `branches`, and `loop`
 * targets. If the diagram looks wrong, the schema is wrong — there is no
 * prose to disagree with.
 */
export function renderMermaid(flow) {
    const lines = ["flowchart TD"];
    const stepById = new Map();
    for (const phase of flow.phases) {
        for (const step of phase.steps) {
            stepById.set(`${phase.id}/${step.id}`, step);
        }
    }
    const nodeId = (key) => key.replace(/[^a-zA-Z0-9]/g, "_");
    // Match the per-target step numbering used elsewhere (computeStepNumbers
    // in render.ts): only count steps reachable for the diagram target, so
    // the Mermaid tab agrees with the rendered markdown / Steps tab.
    const reachable = computeReachableSteps(flow, DIAGRAM_TARGET);
    for (const phase of flow.phases) {
        const phaseTitle = escapeMermaidLabel(resolveTargetableString(phase.title, DIAGRAM_TARGET, "phase.title"));
        lines.push(`  subgraph ${nodeId(phase.id)}["${phaseTitle}"]`);
        let counter = 1;
        for (const step of phase.steps) {
            const stepKey = `${phase.id}/${step.id}`;
            if (!reachable.has(stepKey)) {
                continue;
            }
            const id = nodeId(stepKey);
            const baseLabel = escapeMermaidLabel(resolveTargetableString(step.title, DIAGRAM_TARGET, "step.title"));
            const num = step.preamble === true ? 0 : counter;
            if (step.preamble !== true) {
                counter += 1;
            }
            const label = `${num}. ${baseLabel}`;
            const fork = forkClass(step);
            const cls = fork ?? "step";
            lines.push(`    ${id}["${label}"]:::${cls}`);
        }
        lines.push("  end");
    }
    // Per-mode edges from action / reference / parallel steps. Both endpoints
    // must be reachable for the diagram target — otherwise mermaid would
    // auto-create bare unlabeled nodes outside their subgraphs.
    const modes = Object.keys(flow.entries);
    const seenLinearEdges = new Set();
    const isReachable = (ref) => reachable.has(ref);
    for (const phase of flow.phases) {
        for (const step of phase.steps) {
            const src = `${phase.id}/${step.id}`;
            if (!isReachable(src)) {
                continue;
            }
            if (step.kind === "action" ||
                step.kind === "reference" ||
                step.kind === "parallel") {
                if (step.next === null || typeof step.next === "string") {
                    if (step.next !== null && isReachable(step.next)) {
                        const edge = `${src}->${step.next}`;
                        if (!seenLinearEdges.has(edge)) {
                            seenLinearEdges.add(edge);
                            lines.push(`  ${nodeId(src)} --> ${nodeId(step.next)}`);
                        }
                    }
                }
                else {
                    for (const mode of modes) {
                        const target = step.next.byMode[mode] ?? null;
                        if (target === null || !isReachable(target)) {
                            continue;
                        }
                        lines.push(`  ${nodeId(src)} -->|"${escapeMermaidLabel(mode)}"| ${nodeId(target)}`);
                    }
                }
            }
            else if (step.kind === "branch") {
                for (const branch of step.branches) {
                    const baseLabel = branchLabel(branch);
                    const labelWithRec = branch.recommended
                        ? `${baseLabel} (recommended)`
                        : baseLabel;
                    if (branch.next === null || typeof branch.next === "string") {
                        if (branch.next !== null && !isReachable(branch.next)) {
                            continue;
                        }
                        const target = branch.next === null ? "flow_end" : nodeId(branch.next);
                        lines.push(`  ${nodeId(src)} -->|"${escapeMermaidLabel(labelWithRec)}"| ${target}`);
                    }
                    else {
                        // byMode branch: emit one edge per declared mode, scoped by mode
                        // label so the diagram shows where the option diverges.
                        for (const mode of modes) {
                            const dest = branch.next.byMode[mode] ?? null;
                            if (dest !== null && !isReachable(dest)) {
                                continue;
                            }
                            const target = dest === null ? "flow_end" : nodeId(dest);
                            const modeLabel = `${labelWithRec} [${mode}]`;
                            lines.push(`  ${nodeId(src)} -->|"${escapeMermaidLabel(modeLabel)}"| ${target}`);
                        }
                    }
                }
            }
            else if (step.kind === "loop") {
                if (isReachable(step.backTo)) {
                    lines.push(`  ${nodeId(src)} -.->|"until ${escapeMermaidLabel(step.exitWhen)}"| ${nodeId(step.backTo)}`);
                }
                if (isReachable(step.onExit)) {
                    lines.push(`  ${nodeId(src)} -->|"exit"| ${nodeId(step.onExit)}`);
                }
            }
        }
    }
    // Synthetic end node for terminal branches; only emitted if referenced.
    if (lines.some((l) => l.includes("flow_end"))) {
        lines.push("  flow_end((end)):::terminal");
        lines.push("  classDef terminal fill:#3a1f1f,stroke:#d96a6a,color:#ffd7d7");
    }
    // Entry markers — use the diagram target's resolved entry. Per-target
    // entries fall back to default; if no default and no claude entry, the
    // mode is omitted from the diagram (rare).
    const entryNodeIds = [];
    for (const [mode, entry] of Object.entries(flow.entries)) {
        const resolved = resolvePerTarget(entry, DIAGRAM_TARGET);
        if (resolved === undefined) {
            continue;
        }
        const startId = `start_${nodeId(mode)}`;
        const isDefault = flow.defaultMode === mode;
        const label = isDefault ? `${mode} (default)` : mode;
        lines.push(`  ${startId}(("${escapeMermaidLabel(label)}")):::entry`);
        lines.push(`  ${startId} --> ${nodeId(resolved)}`);
        entryNodeIds.push(startId);
    }
    // Stack entries vertically with invisible links. Without this, modes that
    // all point at the same first step (e.g. `all` / `plugin` / `sdk` in the
    // update flow) cluster horizontally above that step and crowd the page.
    if (entryNodeIds.length > 1) {
        lines.push(`  ${entryNodeIds.join(" ~~~ ")}`);
    }
    lines.push("  classDef entry fill:#1f3a1f,stroke:#5bd58e,color:#d6ffe2");
    // Step + fork classes. Every step renders as a rectangle of the same size;
    // the three fork kinds (mode, user, agent) are signalled purely by
    // background tint so the eye can sweep the spine of the flow uniformly.
    lines.push("  classDef step fill:#262626,stroke:#666,color:#e0e0e0");
    lines.push("  classDef modeFork fill:#1f2a3a,stroke:#7aa2d9,color:#cfe1ff");
    lines.push("  classDef userDecision fill:#2a1f3a,stroke:#b58be0,color:#e8d6ff");
    lines.push("  classDef agentDecision fill:#3a2a1f,stroke:#e0a35b,color:#ffe1c7");
    return lines.join("\n");
}
/**
 * Three fork kinds:
 *   - **mode fork** — an action/reference/parallel step whose `next` is a
 *     `byMode` map: the flow takes different paths per invocation mode
 *     (the edges fan out labeled `all` / `plugin` / `sdk`).
 *   - **user decision** — a `branch` step whose options are tagged with
 *     `option` (rendered as A/B/C in AskUserQuestion).
 *   - **agent decision** — a `branch` step whose options are tagged with
 *     `when` runtime conditions (the agent picks at runtime, no prompt).
 *
 * Mixed branches (some `option`, some `when`) classify as user-decision
 * since the prompt dominates the user-facing experience.
 */
function forkClass(step) {
    if (step.kind === "branch") {
        return branchForkClass(step);
    }
    if (step.kind === "action" ||
        step.kind === "reference" ||
        step.kind === "parallel") {
        if (typeof step.next === "object" && step.next !== null) {
            return "modeFork";
        }
    }
    return null;
}
function branchForkClass(step) {
    const hasOption = step.branches.some((b) => b.option !== undefined);
    return hasOption ? "userDecision" : "agentDecision";
}
function escapeMermaidLabel(s) {
    return s.replace(/"/g, "&quot;").replace(/\|/g, "&#124;");
}
/**
 * Plain-text adjacency dump for quick inspection. Lists each step and its
 * outgoing edges grouped by mode — useful for snapshot tests and as a sanity
 * check that the schema's graph matches expectations.
 */
export function describeFlow(flow) {
    const lines = [];
    const title = resolveTargetableString(flow.title, DIAGRAM_TARGET, "flow.title");
    lines.push(`Flow: ${flow.id} (${title})`);
    if (flow.defaultMode !== undefined) {
        lines.push(`Default mode: ${flow.defaultMode}`);
    }
    lines.push("Entries:");
    for (const [mode, entry] of Object.entries(flow.entries)) {
        const resolved = resolvePerTarget(entry, DIAGRAM_TARGET);
        lines.push(`  ${mode} → ${resolved ?? "<no entry for diagram target>"}`);
    }
    lines.push("");
    for (const phase of flow.phases) {
        lines.push(`Phase: ${phase.id}`);
        for (const step of phase.steps) {
            const key = `${phase.id}/${step.id}`;
            lines.push(`  ${key} [${step.kind}]`);
            const modes = Object.keys(flow.entries);
            for (const mode of modes) {
                const targets = nextRefsForMode(step, mode);
                const desc = targets.map((t) => t ?? "<end>").join(", ");
                lines.push(`    ${mode} → ${desc}`);
            }
        }
    }
    return lines.join("\n");
}
